// Script Continued Below
function onSubmit() {

	var subTasks = g_form.getValue('calchaschildren');
	var taskNumber = g_form.getValue('number');
	var cancelation_confirmation;
	var currentUser = g_user.getFullName();
	var cancelation_reason= '';

	function getCancelationReason() {

		cancelation_reason = prompt("Please provide a reason to why you want to cancel this task: ");
		try {
			if(cancelation_reason == null)
				return false;
			if (cancelation_reason == '' || cancelation_reason == undefined) {

				throw err;
			} else {
				g_form.setValue('u_cancellation_reason', cancelation_reason);
				g_form.setValue('u_canceled_by',currentUser);

			}
		} catch (e){
			alert("You must provide a cancelation reason");
			getCancelationReason();
		}
	}
	// cancel ui aciton for platform cancelation prompt
	if (g_form.getActionName() == 'cancel') {

		if (subTasks > 0) {
			cancelation_confirmation = confirm("Are you sure you want to cancel this task? " + taskNumber + " has " + subTasks + " Subtasks that are also going to be canceled. Do you want to continue?");
		} else {
			cancelation_confirmation = confirm("Are you sure you want to cancel this task?");
		}

		if (cancelation_confirmation == true) {

			getCancelationReason();
			if(cancelation_reason == null)
				return false;
		}else {
			return false;
		}
	}

	// cancel ui action for serviceportal prompt via modal
	if(g_form.getActionName() == 'sp_cancel'){
		if (typeof spModal != 'undefined' ) {
			spModal.open({
				title: 'Cancel ' + g_form.getValue("number") + "?",
				backdrop:'static',
				widget: 'tasker_modal_prompt',
				widgetInput: {'uiAction' : 'cancel', 'taskId': g_form.getUniqueValue(), 'numberOfChildren': g_form.getValue('calchaschildren'), 'taskNumber': g_form.getValue('number')},
					buttons: []
				}).then(function(){
					//jslog("numberofsubtasks");
				}) ;
				return false;	}
			}

		}
